import java.util.*;class Inventory{static class N{int id,q;String n;double p;N next;N(int id,String n,int q,double p){this.id=id;this.n=n;this.q=q;this.p=p;}}static N head;static void add(int id,String n,int q,double p){N t=new N(id,n,q,p);t.next=head;head=t;}static double total(){double s=0;N c=head;while(c!=null){s+=c.q*c.p;c=c.next;}return s;}public static void main(String[] a){add(1,"I1",2,10);add(2,"I2",3,20);System.out.println(total());}}